class Solution {
public:
    int minPathSum(vector<vector<int>>& g) {
        int m=g.size(), n=g[0].size();
        vector<int> dp(g[0].begin(), g[0].end());
        for(int j=1;j<n;j++) dp[j]+=dp[j-1];
        for(int i=1;i<m;i++){
            dp[0]+=g[i][0];
            for(int j=1;j<n;j++) dp[j]=g[i][j]+min(dp[j],dp[j-1]);
        }
        return dp[n-1];
    }
};
